  exportPDF({
    // the incremental flag is ignored in Server-Backed because the resulting PDF is always a fully
    // saved copy of the document.
    flatten = false,
    includeComments = true,
    excludeAnnotations = false,
    outputFormat = false,
    optimize = false,
    flattenElectronicSignatures = flatten,
  }: ExportPDFFlags = {}): Promise<ArrayBuffer> {
    // Throw if `flatten` is set and `flattenElectronicSignatures` is set to `false`.
    // When `flattenElectronicSignatures` is not explicitly set,
    // it defaults  to the value of `flatten`.

    if (flatten && flattenElectronicSignatures === false) {
      throw new PSPDFKitError(
        'Cannot set `flattenElectronicSignatures` to `false` when `flatten` is set to `true`.',
      )
    }

    const url = `${this._state.documentURL}/pdf?token=${this._state.token}${
      flatten ? `&flatten=${String(flatten)}` : ''
    }&comments=${String(includeComments)}&render_ap_streams=${String(
      !flatten,
    )}&remove_annotations=${String(excludeAnnotations)}${
      // Document Engine doesn't even allow to provide a `false` value for `keep_signatures``
      // when flatten is set.
      flatten ? '' : `&keep_signatures=${!flattenElectronicSignatures}`
    }`

    if (optimize) {
      const defaultOptimizationOptions = {
        documentFormat: 'pdf',
        grayscaleText: false,
        grayscaleGraphics: false,
        grayscaleFormFields: false,
        grayscaleAnnotations: false,
        grayscaleImages: false,
        disableImages: false,
        mrcCompression: false,
        imageOptimizationQuality: 2,
        linearize: false,
      }

      let options

      if (typeof optimize !== 'boolean') {
        const mergedObject = { ...defaultOptimizationOptions, ...optimize }
        options = mergedObject
      } else {
        options = defaultOptimizationOptions
      }

      const {
        documentFormat,
        grayscaleText,
        grayscaleGraphics,
        grayscaleFormFields,
        grayscaleAnnotations,
        grayscaleImages,
        disableImages,
        mrcCompression,
        imageOptimizationQuality,
        linearize,
      } = options

      return fetch(url, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          parts: [{ document: { id: '#self' } }],
          output: {
            type: documentFormat,
            grayscaleText,
            grayscaleGraphics,
            grayscaleFormFields,
            grayscaleAnnotations,
            grayscaleImages,
            disableImages,
            mrcCompression,
            imageOptimizationQuality,
            linearize,
          },
        }),
        credentials: 'include',
      }).then(r => r.arrayBuffer())
    }

    if (outputFormat) {
      const defaultSaveAsOptions = {
        conformance: Conformance.PDFA_2B,
        vectorization: true,
        rasterization: true,
      }

      let options

      if (typeof outputFormat !== 'boolean') {
        const mergedObject = { ...defaultSaveAsOptions, ...outputFormat }
        options = mergedObject
      } else {
        options = defaultSaveAsOptions
      }

      const { conformance, vectorization, rasterization } = options

      return fetch(url, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          parts: [{ document: { id: '#self' } }],
          output: {
            type: 'pdfa',
            conformance: conformance,
            vectorization: vectorization,
            rasterization: rasterization,
          },
        }),
        credentials: 'include',
      }).then(r => r.arrayBuffer())
    }

    return fetch(url, {
      method: 'GET',
      credentials: 'include',
    }).then(r => r.arrayBuffer())
  }

