  refreshSignaturesInfo(): Promise<void> {
    if (this._refreshSignaturesInfoPromise) {
      return this._refreshSignaturesInfoPromise
    }

    this._refreshSignaturesInfoPromise = new Promise((resolve, reject) => {
      this._fetch(`${this._state.documentURL}/signatures`, {
        method: 'get',
        credentials: 'include',
      })
        .then(res => res.json())
        .then(({ data: digitalSignatures }) => {
          this._state = this._state.set(
            'digitalSignatures',
            deserializeSignaturesInfo(digitalSignatures),
          )
          this._refreshSignaturesInfoPromise = null
          resolve()
        })
        .catch(error => {
          this._state = this._state.set('digitalSignatures', null)
          this._refreshSignaturesInfoPromise = null
          reject(error)
        })
    })

    return this._refreshSignaturesInfoPromise
  }

  async signDocumentAndReload(
    signaturePreparationData: SignatureCreationData | null | undefined,
    signingServiceData?: SigningServiceData,
  ): Promise<void | string> {
    invariant(
      typeof signingServiceData === 'undefined' || typeof signingServiceData === 'object',
      'Signing service data must be an object if specified.',
    )

    try {
      if (signingServiceData !== undefined && typeof signingServiceData !== 'object') {
        throw new PSPDFKitError('Signing service data must be an object if specified.')
      }

      validateServerSignaturePreparationData(signaturePreparationData)

      const additionalParams = signaturePreparationData
        ? {
            ...('placeholderSize' in signaturePreparationData
              ? { estimatedSize: signaturePreparationData.placeholderSize }
              : null),
            ...('flatten' in signaturePreparationData
              ? { flatten: signaturePreparationData.flatten }
              : null),
            ...(signaturePreparationData?.signatureMetadata
              ? {
                  signatureMetadata: serializeSignatureMetadata(
                    signaturePreparationData.signatureMetadata,
                  ),
                }
              : null),
            ...('position' in signaturePreparationData
              ? { position: serializeSignaturePosition(signaturePreparationData.position) }
              : null),
            ...('appearance' in signaturePreparationData
              ? {
                  appearance: await serializeSignatureAppearance(
                    signaturePreparationData.appearance,
                  ),
                }
              : null),
            ...('formFieldName' in signaturePreparationData
              ? { formFieldName: signaturePreparationData.formFieldName }
              : null),
            ...(typeof signaturePreparationData?.signingData !== 'undefined' &&
            'signatureContainer' in signaturePreparationData.signingData
              ? { signatureContainer: signaturePreparationData.signingData.signatureContainer }
              : null),
            ...(typeof signaturePreparationData?.signingData !== 'undefined' &&
            'signatureType' in signaturePreparationData.signingData
              ? {
                  signatureType:
                    signatureTypeMappingForCore[signaturePreparationData.signingData.signatureType],
                }
              : null),
          }
        : null

      const image = signaturePreparationData?.appearance?.watermarkImage || null
      const graphicImage = signaturePreparationData?.appearance?.graphicImage || null

      const body = {
        ...(signingServiceData
          ? {
              signingToken: signingServiceData.signingToken,
            }
          : null),
        ...additionalParams,
      }

      const formData = new FormData()
      formData.append('data', JSON.stringify(body))
      image && formData.append('image', image)
      graphicImage && formData.append('graphicImage', graphicImage)

      // We destroy the provider because during signing, a new form field and
      // widget annotation are created. Afterwards, we reload the document and
      // update the layerHandle, bailing out from the changes propagation back
      // to the managers flow.
      this._destroyProvider()

      await this._fetch(`${this._state.documentURL}/sign`, {
        method: 'post',
        body: formData,
        credentials: 'include',
      })

      await this.reloadDocument()

      if (signaturePreparationData?.formFieldName) {
        return signaturePreparationData.formFieldName
      }
    } catch (e) {
      // We rollback from destroying the provider if signing fails. Otherwise,
      // no further updates are sent to the current provider.
      this.provider.load()
      throw new PSPDFKitError(`Adding digital signature failed: ${e.message || e}`)
    }
  }

