function parseAsJSONOrString(response: Response) {
  // The response stream needs to be cloned before attempting
  // to read from it again (in case we need to fallback to text
  // parsing)
  return response
    .clone()
    .json()
    .catch(() => response.text())
}

async function createOperationsPayload(operations) {
  const operationsDocuments = {}
  // If multiple operations use the same blob, we only want to send it once.
  // We track blobs that have already been appended in a WeakMap(blob => index)
  const blobWeakMap = new WeakMap()
  const processedOperations = await Promise.all(
    operations.map(async (operation, index): Promise<DocumentOperationJSON> => {
      if (operation.type === 'importDocument') {
        const document = operation.document

        invariant(
          document instanceof File || document instanceof Blob,
          'Wrong `importDocument` operation `document` value: it must be a File or a Blob',
        )

        return addBlobToWeakMap(
          blobWeakMap,
          operationsDocuments,
          document,
          operation,
          index,
          'document',
        )
      } else if (operation.type === 'applyInstantJson') {
        const value = operation.instantJson

        invariant(
          typeof value === 'object' && value !== null,
          'Wrong `applyInstantJson` operation `instantJson` value: it must be an object',
        )

        const string = JSON.stringify(value)
        const document = new Blob([string], {
          type: 'application/json',
        })

        return addBlobToWeakMap(
          blobWeakMap,
          operationsDocuments,
          document,
          operation,
          index,
          'dataFilePath',
        )
      } else if (operation.type === 'applyXfdf') {
        const value = operation.xfdf

        invariant(
          typeof value === 'string',
          'Wrong `applyXfdf` operation `xfdf` value: it must be a string',
        )

        const document = new Blob([value], {
          type: 'application/vnd.adobe.xfdf',
        })

        return addBlobToWeakMap(
          blobWeakMap,
          operationsDocuments,
          document,
          operation,
          index,
          'dataFilePath',
        )
      }

      return operation
    }),
  )
  const formData = new FormData()

  formData.append(
    'operations',
    JSON.stringify({
      operations: processedOperations,
    }),
  )

  for (const document in operationsDocuments) {
    formData.append(document, operationsDocuments[document])
  }

  return formData
}

function validateInstantSetting(instant: boolean | InstantSettings) {
  let error = ''

  // Validate instant property.
  if (typeof instant !== 'boolean') {
    if (isPlainObject(instant)) {
      if (
        instant.hasOwnProperty('clientsPresenceEnabled') &&
        typeof instant['clientsPresenceEnabled'] !== 'boolean'
      ) {
        error +=
          '`clientsPresenceEnabled` in instance settings is not valid. Must be `true` or `false`.\n'
      }

      if (
        instant.hasOwnProperty('listenToServerChangesEnabled') &&
        typeof instant['listenToServerChangesEnabled'] !== 'boolean'
      ) {
        error +=
          '`listenToServerChangesEnabled` in instance settings is not valid. Must be `true` or `false`.\n'
      }
    } else {
      error = '`instant` flag must either be set to `true` or `false`\n'
    }

    if (error) {
      throw new PSPDFKitError(`${error}
For more information about PSPDFKit Instant please visit:
https://pspdfkit.com/guides/web/current/instant/overview/`)
    }
  }
}

function resolveServerUrl(configuration: ServerConfiguration, _window: Window = window): string {
  const serverUrl = configuration.serverUrl || getBaseUrl(_window.document)

  // serverUrl must have a slash at the end
  if (serverUrl.substr(-1) !== '/') {
    throw new PSPDFKitError(
      '`serverUrl` must have a slash at the end (e.g. `https://pspdfkit.example.com/`).',
    )
  }

  // Verify that the base URL is different from the current browser's location. If it's the same,
  // we assume that we haven't loaded PSPDFKit for Web from the Server origin and bail out. If
  // the `serverUrl` is explicitly set in the configuration, we will always use it
  if (!configuration.serverUrl) {
    // There were some problems with `window.location.origin` in IE11 on Win10 [1], that's why
    // we use `window.location.host` instead.
    // [1]: https://goo.gl/5D5mNX
    const browserOrigin = `${_window.location.protocol}//${_window.location.host}/`

    if (serverUrl === browserOrigin) {
      throw new PSPDFKitError(`PSPDFKit automatically infers the URL of PSPDFKit Document Engine from the current \`<script>\` tag.
In the current case, this URL is set to the same as the current browser's location.
This can happen when you bundle pspdfkit.js with your custom JavaScript for example.

To make sure everything works as expected, please set the \`serverUrl\` to the URL of PSPDFKit Document Engine:

PSPDFKit.load({
  serverUrl: "https://pspdfkit-server.example.com/",
  ...,
});`)
    }
  }

  return serverUrl
}
