import { PSPDFKitError, warn } from '@pspdfkit/shared'

import { requestIsSuccess } from '@/utils/http'
import { webp } from '@/utils/features'
import ImageHandle from '../../handles/ImageHandle'
import { getVersionHeader } from '@/utils/environment'
import { isChrome } from '@/utils/browser'

import type { Request } from '@pspdfkit/main-only'

const GENERIC_RENDER_ERROR = 'The image can not be rendered because of an unknown error.'

export default class XHRImageRequest implements Request {
  identifier: string
  token: string
  url: string
  payload: any
  httpRequest?: XMLHttpRequest
  doNotRequestWebP: boolean

  constructor({
    identifier,
    url,
    token,
    payload,
    doNotRequestWebP = false,
  }: {
    identifier: string
    url: string
    token: string
    payload?: any
    doNotRequestWebP?: boolean
  }) {
    this.identifier = identifier
    this.url = url
    this.token = token
    this.payload = payload
    this.doNotRequestWebP = doNotRequestWebP
  }

  abort(): void {
    this.httpRequest?.abort()
  }

  request(): Promise<
    | ImageHandle<HTMLImageElement>
    | null
    | {
        attachmentsNotFound: Array<string>
      }
  > {
    return new Promise((resolve, reject) => {
      const httpRequest = new XMLHttpRequest()

      this.httpRequest = httpRequest
      httpRequest.open(this.payload ? 'POST' : 'GET', this.url, true)
      httpRequest.setRequestHeader('X-PSPDFKit-Image-Token', this.token)
      httpRequest.setRequestHeader('PSPDFKit-Platform', 'web')
      httpRequest.setRequestHeader('PSPDFKit-Version', getVersionHeader())

      if (webp && !this.doNotRequestWebP) {
        httpRequest.setRequestHeader('Accept', 'image/webp,*/*')
      }

      httpRequest.responseType = 'blob'

      // We need to use the spec conform `onreadystatechange` since `onload` and `onerror` behaves
      // differently in our test environment
      // @TODO inspect what's causing the context of the arrow function to change
      httpRequest.onreadystatechange = (async () => {
        // request finished and response is ready
        if (httpRequest.readyState !== 4) {
          return
        }

        // response.type can include charset info, so we only check it begins with application/json
        if (httpRequest.response && httpRequest.response.type.startsWith('application/json')) {
          // We have to read the blob here using a FileReader since we configure the http request as
          // a blob one.
          const fileReader = new FileReader()

          fileReader.onload = event => {
            const response = JSON.parse(event.target?.result as string)

            if (response.attachments_not_found) {
              resolve({
                attachmentsNotFound: response.attachments_not_found,
              })
            } else if (response.error) {
              if (response.error === 'initialization_error') {
                if (process.env.NODE_ENV !== 'production') {
                  warn(
                    'The server could not render the requested image because of an initialization error: maybe tried to render an empty AP stream, which happens often with link annotations.',
                  )
                }

                resolve(null)
              } else {
                reject(
                  new PSPDFKitError(
                    `The server could not render the requested image (${response.error})`,
                  ),
                )
              }
            } else {
              reject(new PSPDFKitError(GENERIC_RENDER_ERROR))
            }
          }

          fileReader.onerror = () => reject(new PSPDFKitError(GENERIC_RENDER_ERROR))

          fileReader.readAsText(httpRequest.response)

          return
        }

        if (!requestIsSuccess(httpRequest.status)) {
          reject(new PSPDFKitError(GENERIC_RENDER_ERROR))

          return
        }

        const blob = httpRequest.response
        const objectUrl = URL.createObjectURL(blob)
        const img = new Image()

        img.onerror = () => reject(new PSPDFKitError(GENERIC_RENDER_ERROR))

        img.src = objectUrl

        const imagePromise = img.decode()

        try {
          // We want to ensure that the image has been decoded before using it,
          // so we await the image decoding promise.
          await imagePromise
        } catch (error) {
          // Sometimes decode() throws in Chrome. The reasons are not clear yet, but seems
          // to happen with tiles, when there are many images to render.
          if (isChrome) {
            // In that case we give up decode() and just wait for the timeout instead.
            await new Promise(resolve => setTimeout(resolve, 200))
          } else {
            throw new PSPDFKitError(`The image could not be decoded: ${error.message}`)
          }
        }

        resolve(new ImageHandle(img, () => URL.revokeObjectURL(objectUrl)))
      }).bind(this)

      httpRequest.send(this.payload)
    })
  }
}
