import { PSPDFKitError } from '@pspdfkit/shared'

import { getVersionHeader } from '@/utils/environment'

import type { ILicenseFeature } from '@/enums/LicenseFeature'
import type { SignaturesInfoJSON } from '@pspdfkit/core'
import type { ISignatureFeatureAvailability } from '@/enums/SignatureFeatureAvailability'

export type AuthResponse = {
  imageToken: string
  token: string
  permissions: Array<string>
  features: Array<ILicenseFeature>
  signatureFeatureAvailability: ISignatureFeatureAvailability
  hasPassword: boolean
  minSearchQueryLength: number
  layerHandle: string
  allowedTileScales: 'all' | Array<number>
  digitalSignatures: SignaturesInfoJSON
  defaultGroup: string | undefined
  creatorName: string | undefined
  collaborationPermissions?: Record<string, any>

  // Both serverVersion and documentEngineVersion fields
  // are kept here to ensure Web can still work with old versions of Server
  // after the Document Engine release

  // This field is available for legacy versions of Document Engine i.e PSPDFKit Document Engine up to 2024.1.x
  serverVersion?: string | undefined

  // This field is available for PSPDFKit Document Engine from 1.0.0 onwards
  documentEngineVersion?: string | undefined

  // Token that can be used to initialize Core.
  wasmToken?: string
}

/**
 * Calls the `/auth` endpoint and generates the tokens.
 */
export async function authenticate(
  documentURL: string,
  authPayload: {
    jwt: string
  },
  password?: string | null,
): Promise<AuthResponse> {
  const res = await fetch(`${documentURL}/auth`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'PSPDFKit-Platform': 'web',
      'PSPDFKit-Version': getVersionHeader(),
    },
    body: JSON.stringify({
      jwt: authPayload.jwt,
      // IE11 does not send `Origin` headers for some requests, since it has a different
      // understanding of the origin spec. To still be able to verify the origin in the IE11 case,
      // we add that information as payload manually.
      // There were some problems with `window.location.origin` in IE11 on Win10 [1], that's why
      // we use `window.location.href` instead.
      // [1]: https://goo.gl/5D5mNX
      origin: window.location.href,
      password: password,
    }),
    credentials: 'include',
  })

  if (res.ok) {
    return res.json()
  } else {
    return res.text().then(message => {
      if (message === 'INVALID_PASSWORD') {
        throw new PSPDFKitError(message)
      } else {
        throw new PSPDFKitError(
          `An error occurred while connecting to PSPDFKit Document Engine: ${
            message || res.statusText
          }`,
        )
      }
    })
  }
}
